const amqp = require('amqplib');

class PaymentConsumer {
  constructor() {
    this.connection = null;
    this.channel = null;
    this.queue = 'payment_events';
  }

  async connect() {
    try {
      this.connection = await amqp.connect('amqp://localhost');
      this.channel = await this.connection.createChannel();
      await this.channel.assertQueue(this.queue, { durable: true });
      await this.channel.prefetch(1);
      console.log('Connected to RabbitMQ');
    } catch (error) {
      console.error('Failed to connect to RabbitMQ:', error);
      throw error;
    }
  }

  async consume() {
    try {
      await this.channel.consume(this.queue, async (msg) => {
        if (msg !== null) {
          try {
            const paymentData = JSON.parse(msg.content.toString());
            await this.processPayment(paymentData);
            this.channel.ack(msg);
          } catch (error) {
            console.error('Error processing payment:', error);
            this.channel.nack(msg, false, false);
          }
        }
      });
    } catch (error) {
      console.error('Error consuming messages:', error);
    }
  }

  async processPayment(paymentData) {
    try {
      console.log('Processing payment:', paymentData);
      
      // Simulate payment processing logic
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      // Execute payment logic based on message content
      if (paymentData.type === 'charge') {
        await this.executeCharge(paymentData);
      } else if (paymentData.type === 'refund') {
        await this.executeRefund(paymentData);
      }
      
      console.log('Payment processed successfully');
    } catch (error) {
      console.error('Payment processing failed:', error);
      throw error;
    }
  }

  async executeCharge(paymentData) {
    // Payment charge logic
    console.log('Executing charge for amount:', paymentData.amount);
    // Simulate API call
    await new Promise(resolve => setTimeout(resolve, 500));
  }

  async executeRefund(paymentData) {
    // Payment refund logic
    console.log('Executing refund for amount:', paymentData.amount);
    // Simulate API call
    await new Promise(resolve => setTimeout(resolve, 500));
  }

  async close() {
    if (this.channel) {
      await this.channel.close();
    }
    if (this.connection) {
      await this.connection.close();
    }
  }
}

